SELECT count(*) FROM movie_companies, company_type, title, movie_keyword, company_name, kind_type, keyword, movie_info WHERE movie_companies.company_type_id = company_type.id AND movie_companies.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_companies.company_id = company_name.id AND title.kind_id = kind_type.id AND movie_keyword.keyword_id = keyword.id AND movie_info.movie_id = title.id;